checker_dsl:
EXISTS (`method call MA`, `constructor C`) {
  EXISTS (`method M`, `method N`) {
    EXISTS (`field F`, `field read FA`) {
      EXISTS (`constructor D`, `field write FW`) {
        AND {
          (`MA is a method call whose enclosing callable is constructor C, has no qualifier or a ThisAccess qualifier whose type is the same as the declaring type of constructor C, and the method called by MA is M`),
          (`M is not an abstract method and the declaring type of M is an ancestor (same class or superclass) of the declaring type of constructor C`),
          (`N directly or indirectly overrides M and the declaring type of N is a strict ancestor (proper superclass) of the declaring type of constructor C`),
          (`F is not a final field, the declaring type of F is a strict ancestor (proper superclass) of the declaring type of constructor C, and FA is a field read whose field is F`),
          (`FW is a field write whose field is F`),
          EXISTS (`callable WRITER`) {
            AND {
              (`WRITER writes field F`),
              (`the total number of distinct callables that write field F in the entire codebase is exactly 1`)
            }
          },
          (`constructor D directly or indirectly calls constructor C`)
        }
      }
    }
  }
}
